import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";

export const useLogoutHandler = () => {
  const navigate = useNavigate();
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const isModalTriggeredRef = useRef(false);

  // Handle logout
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setShowLogoutModal(false);
    navigate("/login", { replace: true });
  };

  // Prevent back button navigation to login page
  useEffect(() => {
    // Push a new history state to prevent going back
    window.history.pushState(null, null, window.location.pathname);

    // Listen for back button clicks
    const handlePopState = () => {
      // Only show logout modal if it hasn't been triggered yet
      if (!isModalTriggeredRef.current) {
        isModalTriggeredRef.current = true;
        setShowLogoutModal(true);
        // Push state again to stay on current page
        window.history.pushState(null, null, window.location.pathname);
      }
    };

    window.addEventListener("popstate", handlePopState);

    return () => {
      window.removeEventListener("popstate", handlePopState);
    };
  }, []);

  // Reset the flag when modal is closed
  const setShowLogoutModalWithReset = (value) => {
    setShowLogoutModal(value);
    if (!value) {
      isModalTriggeredRef.current = false;
    }
  };

  return { handleLogout, showLogoutModal, setShowLogoutModal: setShowLogoutModalWithReset };
};
